(function(){'use strict';class GHLFormAutoFill{constructor(){this.initialized=!1;this.ghlDomains=['link.leadconnectorhq.com','link.gohighlevel.com','link.msgsndr.com','form.leadconnectorhq.com'];this.config=typeof ghl_form_autofill_data!=='undefined'?ghl_form_autofill_data:{};this.userData=this.config.userData||{};this.formSettings=this.config.formSettings||{};this.whiteLabelDomain=this.config.whiteLabelDomain||'';if(this.whiteLabelDomain){try{const domain=new URL(this.whiteLabelDomain).hostname;if(domain&&!this.ghlDomains.includes(domain)){this.ghlDomains.push(domain)}}catch(e){}}}
init(){if(this.initialized){return}
if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',()=>this.processIframes())}else{this.processIframes()}
this.observeNewIframes();this.initialized=!0}
isGHLFormIframe(iframe){const src=iframe.getAttribute('src');if(!src){return!1}
return this.ghlDomains.some(domain=>src.includes(domain))}
getPreFillData(){if(Object.keys(this.userData).length>0){return this.userData}
return{}}
extractFormId(src){try{const url=new URL(src);const pathParts=url.pathname.split('/');const formId=pathParts[pathParts.length-1];return formId||null}catch(e){return null}}
isAutofillEnabled(formId){if(!formId){return!0}
const settings=this.formSettings[formId];if(!settings){return!0}
return settings.autofill_enabled!==!1}
getCustomParams(formId){if(!formId){return{}}
const settings=this.formSettings[formId];if(!settings||!settings.resolved_params){return{}}
const params={...settings.resolved_params};Object.keys(params).forEach(key=>{let value=params[key];if(value.includes('{current_url}')){value=value.replace('{current_url}',window.location.href)}
if(value.includes('{current_title}')){value=value.replace('{current_title}',document.title)}
params[key]=value});return params}
buildQueryString(data){const params=new URLSearchParams();for(const[key,value]of Object.entries(data)){if(value){params.append(key,value)}}
return params.toString()}
modifyIframeSrc(iframe){const currentSrc=iframe.getAttribute('src');if(!currentSrc){return}
if(iframe.dataset.ghlAutofilled==='true'){return}
try{const url=new URL(currentSrc);const formId=this.extractFormId(currentSrc);if(!this.isAutofillEnabled(formId)){iframe.dataset.ghlAutofilled='skipped';return}
const preFillData=this.getPreFillData();const customParams=this.getCustomParams(formId);const finalParams={...preFillData,...customParams};if(Object.keys(finalParams).length===0){return}
for(const[key,value]of Object.entries(finalParams)){if(!url.searchParams.has(key)&&value){url.searchParams.set(key,value)}}
const newSrc=url.toString();if(newSrc!==currentSrc){iframe.setAttribute('src',newSrc);iframe.dataset.ghlAutofilled='true'}}catch(error){}}
processIframes(){const iframes=document.querySelectorAll('iframe');iframes.forEach(iframe=>{if(this.isGHLFormIframe(iframe)){this.modifyIframeSrc(iframe)}})}
observeNewIframes(){const observer=new MutationObserver(mutations=>{mutations.forEach(mutation=>{mutation.addedNodes.forEach(node=>{if(node.nodeName==='IFRAME'&&this.isGHLFormIframe(node)){this.modifyIframeSrc(node)}
if(node.querySelectorAll){const iframes=node.querySelectorAll('iframe');iframes.forEach(iframe=>{if(this.isGHLFormIframe(iframe)){this.modifyIframeSrc(iframe)}})}})})});observer.observe(document.body,{childList:!0,subtree:!0})}}
const autoFill=new GHLFormAutoFill();autoFill.init();window.ghlFormAutoFill=autoFill;window.testGHLAutoFill=function(){autoFill.processIframes()};function initSubmissionTracking(){const trackedForms=new Set();document.querySelectorAll('.ghl-form-wrapper[data-track-submission="1"]').forEach(wrapper=>{const formId=wrapper.dataset.formId;if(formId){trackedForms.add(formId)}});window.addEventListener('message',function(event){const ghlDomains=autoFill.ghlDomains;let isGHLDomain=!1;try{const origin=new URL(event.origin).hostname;isGHLDomain=ghlDomains.some(domain=>origin.includes(domain))}catch(e){return}
if(!isGHLDomain)return;if(Array.isArray(event.data)&&event.data[0]==='set-sticky-contacts'){const dataString=event.data[2];if(dataString&&typeof dataString==='string'){try{const parsedData=JSON.parse(dataString);if(parsedData.customer_id||parsedData.email){const iframes=document.querySelectorAll('iframe[data-form-id]');iframes.forEach(iframe=>{if(iframe.contentWindow===event.source){const formId=iframe.dataset.formId;const wrapper=iframe.closest('.ghl-form-wrapper');if(formId&&trackedForms.has(formId)&&wrapper){markFormAsSubmitted(formId,wrapper)}}})}}catch(e){}}}})}
function markFormAsSubmitted(formId,wrapper){const data=typeof ghl_form_autofill_data!=='undefined'?ghl_form_autofill_data:{};fetch(data.ajaxUrl||'/wp-admin/admin-ajax.php',{method:'POST',headers:{'Content-Type':'application/x-www-form-urlencoded'},body:new URLSearchParams({action:'ghl_mark_form_submitted',nonce:data.nonce||'',form_id:formId})}).then(response=>response.json()).then(result=>{if(result.success){const settings=autoFill.formSettings[formId];if(settings&&settings.submission_limit==='once'){const message=settings.submitted_message||'';if(message){wrapper.innerHTML='<div style="padding: 20px; background: #d4edda; border: 1px solid #c3e6cb; border-radius: 4px; color: #155724; text-align: center;">'+message.replace(/\n/g,'<br>')+'</div>'}else{wrapper.innerHTML=''}}}}).catch(err=>{})}
if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',initSubmissionTracking)}else{initSubmissionTracking()}})()